#include <bits/stdc++.h>
using namespace std;
const int N=2e6+6;
int n,q;
bool t[N];
char s[N];
void build(int cur,int l,int r){
    if(l==r){
        t[cur]=s[l]-'A';
        return;
    }
    int mid1=l+(r-l+1)/3-1,mid2=l+2*(r-l+1)/3-1;
    build(cur*3-1,l,mid1);
    build(cur*3,mid1+1,mid2);
    build(cur*3+1,mid2+1,r);
    t[cur]=(t[cur*3-1]+t[cur*3]+t[cur*3+1]>1);
}
void modify(int cur,int l,int r,int x){
    if(l==r && l==x){
        t[cur]^=1;
        return;
    }
    int mid1=l+(r-l+1)/3-1,mid2=l+2*(r-l+1)/3-1;
    if(x<=mid1)
        modify(cur*3-1,l,mid1,x);
    else if(x<=mid2)
        modify(cur*3,mid1+1,mid2,x);
    else
        modify(cur*3+1,mid2+1,r,x);
    t[cur]=(t[cur*3-1]+t[cur*3]+t[cur*3+1]>1);
}
int main(){
    scanf("%d%d",&n,&q);
    scanf("%s",s+1);
    n=strlen(s+1);
    build(1,1,n);
    while(q--){
        int p;
        scanf("%d",&p);
        modify(1,1,n,p);
        printf("%c\n",t[1]+'A');
    }
    return 0;
}
